VALUES
  ('optometrist-moex-03404', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '在進行近點聚合（near point of convergence, NPC）測驗時，若一開始受測者的雙眼朝內移動，接著一隻眼 睛朝外移（turn outward），此時可能發生下列何種情況？', '["受測者有內聚力過度（convergence excess）", "受測者有抑制（suppression）", "受測者有弱視（amblyopia）", "受測者有斜視（tropia）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "f7b376e4f4b0", "answer_pdf_sha1": "0976f3d6476a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03405', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '關於視力檢查，下列何者錯誤？', '["史耐倫視力表（Snellen visual acuity）是僅以C為測試字母", "史耐倫視力表行與行之間的字母大小，彼此之間沒有呈現一個規則的幾何上的或對數上的關係", "測試結果視力為6/7.5，也可以表示為0.8", "6/6的視標，在正常的測試距離所形成的視覺夾角（visual angle）為5分角（5 arcmin）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "f7b376e4f4b0", "answer_pdf_sha1": "0976f3d6476a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03406', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '關於雙眼視覺機能檢查，下列何者錯誤？', '["魏氏四點檢查（Worth four-dot test）是用來檢測是否有抑制盲區（suppression scotoma）", "立體感的檢測，使用輪廓式的立體圖（contour stereopsis test）可以避免單眼的提示線索（monocular cue）， 病人比較不容易猜對", "紅色鏡片檢測（red-glass test）可以得知病人是否有抑制現象（suppression）", "巴戈里尼鏡片（Bagolini lenses）可以測試視網膜的對應（retinal correspondence）與抑制現象"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "f7b376e4f4b0", "answer_pdf_sha1": "0976f3d6476a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03407', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '下列何者不是後天性麻痺性斜視（paralytic strabismus）之特徵？', '["各個方向所測量的角度不一致（非共同性斜視，nonconcomitant strabismus）", "對同一個目標所測量的斜視角度，第二偏位（secondary deviation）比第一偏位（primary deviation）大", "少有複視的症狀", "頭部常會向麻痺肌作用方向傾斜（眼性斜頸，ocular torticollis）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "f7b376e4f4b0", "answer_pdf_sha1": "0976f3d6476a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03408', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '對弱視治療之敘述，下列何者錯誤？', '["遮蔽性弱視要先將遮蔽的因素去除，例如執行白內障手術、眼瞼下垂矯正", "遮蓋治療越久越好，尤其要在黃金期（六歲前）執行，故必需每天且整天遮眼治療", "配戴正確的眼鏡矯正屈調問題也很重要", "若不能配合遮蓋治療，有時可以在沒弱視眼點藥水（例如阿托平；atropine）使其視力模糊，達到訓練 弱視眼的目的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "f7b376e4f4b0", "answer_pdf_sha1": "0976f3d6476a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03409', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '關於眼球運動的測試檢查，下列何者不適當？', '["往內上看主要靠下斜肌", "往外側看主要靠外直肌", "往內下看主要靠下直肌", "往內側看主要靠內直肌"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "f7b376e4f4b0", "answer_pdf_sha1": "0976f3d6476a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03410', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '一位車禍外傷的病人，主訴有複影，下列的狀況何者較不可能發生？', '["使用雙馬竇氏鏡（double Maddox rod test）發現有兩條不平行的線，表示這個病人有水平性的斜視", "使用遮蓋測試（cover test）發現病人眼睛會上下移動，表示這個病人有上下斜視", "在上下斜視病人右眼的前面加上基底朝下的稜鏡，可以讓病人的眼睛在稜鏡交替遮蓋檢查（prism alternate cover test）中不移動，表示這個病人有右眼上斜視", "在"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "f7b376e4f4b0", "answer_pdf_sha1": "0976f3d6476a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03411', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '若在為病人做電腦驗光檢查時，發現同一位病人在相近時間內（例如半小時內），未使用任何藥物的狀 況下屈光值有很大的變動，可能要進一步檢查，下列何者最不可能是屈光值變動的原因？', '["高度近視合併後葡萄腫（posterior staphyloma）", "水晶體移位（lens subluxation）", "視網膜剝離", "低眼壓型青光眼"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "f7b376e4f4b0", "answer_pdf_sha1": "0976f3d6476a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03412', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '一位病患抱怨有水平複視，左眼看到的影像在左方，右眼看到的影像在右方，經稜鏡遮蔽法測量其斜視 的角度為5個稜鏡度。請問用稜鏡眼鏡矯正可以如何放置？', '["右眼5個稜鏡度，基底朝內", "左眼5個稜鏡度，基底朝內", "右眼3個稜鏡度，左眼2個稜鏡度，均為基底朝外", "右眼2個稜鏡度，基底朝內；左眼3個稜鏡度，基底朝外"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "f7b376e4f4b0", "answer_pdf_sha1": "0976f3d6476a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03413', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '下列何者是自動驗光儀（autorefractor）設計製作所依據的驗光原理？①夏伊納原則（Scheiner’s principle）', '["視網膜檢影鏡原則（retinoscopic principle）", "普倫提西氏法則（Prentice’s rule）", "僅", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "f7b376e4f4b0", "answer_pdf_sha1": "0976f3d6476a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 36, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
